	readJSON(t, resp, &updated)

	due, hasDue := dueAtFromResponse(updated)
	if !hasDue {
		t.Fatal("due should be set after advance_recurrence")
	}
	// Due should have advanced by one week from threeDaysAgo.
	newDue, err := time.Parse("2006-01-02", due)
	if err != nil {
