package taskengine

import (
	"github.com/jackc/pgx/v5/pgtype"
	dbgen "github.com/sargunv/tend/server/internal/database/gen"
	"github.com/sargunv/tend/server/internal/types"
)

// recurrenceAdvancesDue reports whether a recurrence type drives the due date
// forward via a recurrence rule that advance_recurrence can step to the next
// occurrence of. one_off and on_dependency carry no recurrence rule, and
// fixed_accumulating's accumulating cron owns due-date advancement.
func recurrenceAdvancesDue(t dbgen.RecurrenceType) bool {
	return t == dbgen.RecurrenceTypeCompletionBased || t == dbgen.RecurrenceTypeFixedNonAccumulating
}

// ValidateOverdueActionRule checks that an overdue action rule is compatible
// with the task's recurrence type and due date configuration.
//
//   - set_status and clear_due_date are meaningful for any task with a due
//     date, including one_off and on_dependency tasks.
//   - advance_recurrence steps the recurrence rule to its next occurrence, so
//     it is only valid on recurrence-driven types whose due date advances via
//     a recurrence rule (completion_based or fixed_non_accumulating).
func ValidateOverdueActionRule(
	afterDays pgtype.Int4,
	action dbgen.NullOverdueAction,
	statusName pgtype.Text,
	recurrenceType dbgen.RecurrenceType,
	hasDue bool,
) error {
	if !action.Valid {
		return nil // no rule, nothing to validate
	}
	if !hasDue {
		return types.ValidationError("overdue_action_rule requires a due date")
	}
	if action.OverdueAction == dbgen.OverdueActionAdvanceRecurrence && !recurrenceAdvancesDue(recurrenceType) {
		switch recurrenceType {
		case dbgen.RecurrenceTypeFixedAccumulating:
			return types.ValidationError(
				"advance_recurrence overdue action is not supported on fixed_accumulating tasks; " +
					"the accumulating cron handles missed occurrences automatically",
			)
		default:
			return types.ValidationError(
				"advance_recurrence overdue action requires a recurrence-driven task " +
					"(completion_based or fixed_non_accumulating)",
			)
		}
	}
	if action.OverdueAction == dbgen.OverdueActionSetStatus && !statusName.Valid {
		return types.ValidationError("overdue_action_rule.status is required when action is set_status")
	}
	return nil
}

package taskengine

import (
	"strings"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"

	dbgen "github.com/sargunv/tend/server/internal/database/gen"
)

func nullOverdueAction(a dbgen.OverdueAction) dbgen.NullOverdueAction {
	return dbgen.NullOverdueAction{OverdueAction: a, Valid: true}
}

func status(s string) pgtype.Text {
	return pgtype.Text{String: s, Valid: true}
}

func TestValidateOverdueActionRule(t *testing.T) {
	allTypes := []dbgen.RecurrenceType{
		dbgen.RecurrenceTypeOneOff,
		dbgen.RecurrenceTypeOnDependency,
		dbgen.RecurrenceTypeCompletionBased,
		dbgen.RecurrenceTypeFixedNonAccumulating,
		dbgen.RecurrenceTypeFixedAccumulating,
	}

	tests := []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}{
		// ─── No rule ─────────────────────────────────────────────────────────────────
		{
			name:           "nil rule always valid",
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        false,
		},

		// ─── advance_recurrence: only valid on completion_based / fixed_non_accumulating
		{
			name:           "advance_recurrence on one_off rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "requires a recurrence-driven task",
		},
		{
			name:           "advance_recurrence on on_dependency rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        true,
			errContains:    "requires a recurrence-driven task",
		},
		{
			name:           "advance_recurrence on fixed_accumulating rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        true,
			errContains:    "not supported on fixed_accumulating",
		},
		{
			name:           "advance_recurrence on completion_based accepted",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
		},
		{
			name:           "advance_recurrence on fixed_non_accumulating accepted",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
		},

		// ─── due date is required by every action ────────────────────────────────────
		{
			name:           "any action requires a due date",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},

		// ─── set_status needs a status name ──────────────────────────────────────────
		{
			name:           "set_status without status name rejected",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateOverdueActionRule(tc.afterDays, tc.action, tc.statusName, tc.recurrenceType, tc.hasDue)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				if tc.errContains != "" && !strings.Contains(err.Error(), tc.errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), tc.errContains)
				}
			} else if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
		})
	}

	// ─── Matrix: set_status & clear_due_date valid for every recurrence type ───────
	// This is the core of the fix: one_off and on_dependency tasks are eligible.
	for _, rt := range allTypes {
		for _, a := range []dbgen.OverdueAction{dbgen.OverdueActionSetStatus, dbgen.OverdueActionClearDueDate} {
			name := a.String() + "_on_" + rt.String() + "_accepted"
			t.Run(name, func(t *testing.T) {
				tc := struct {
					action     dbgen.NullOverdueAction
					statusName pgtype.Text
				}{
					action: nullOverdueAction(a),
				}
				if a == dbgen.OverdueActionSetStatus {
					tc.statusName = status("overdue")
				}
				if err := ValidateOverdueActionRule(pgtype.Int4{}, tc.action, tc.statusName, rt, true); err != nil {
					t.Fatalf("expected %s to be valid on %s, got: %v", a, rt, err)
				}
			})
		}
	}
}

